using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }

    /// <summary>
    /// Number of sentences in the original document.
    /// </summary>
    public int OriginalSentenceCount { get; set; }

    /// <summary>
    /// Number of sentences kept in the summary.
    /// </summary>
    public int SummarySentenceCount { get; set; }
}

using DocSummary.Models;

namespace DocSummary.Services;

public interface ISummarizationService
{
    SummarizeResponse Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that scores sentences by normalised word-frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class ExtractiveSummarizationService : ISummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","i","you","he","she","it",
        "we","they","me","him","her","us","them","my","your","his","its","our",
        "their","this","that","these","those","in","on","at","to","for","of",
        "with","by","from","as","into","about","between","through","during",
        "before","after","above","below","not","no","nor","so","if","then",
        "than","too","very","just","also","more","most","such","only","own",
        "same","other","each","every","all","any","both","few","some","many",
        "much","how","what","which","who","whom","when","where","why"
    };

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"[^\w\s]")]
    private static partial Regex PunctuationStripper();

    public SummarizeResponse Summarize(string text, int maxSentences)
    {
        var sentences = SentenceSplitter()
            .Split(text.Trim())
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToList();

        if (sentences.Count == 0)
            return new SummarizeResponse
            {
                Summary = string.Empty,
                OriginalSentenceCount = 0,
                SummarySentenceCount = 0
            };

        int keep = Math.Min(maxSentences, sentences.Count);

        // Tokenise and compute word frequencies (ignoring stop-words).
        var wordFreq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        var tokensBySentence = new List<string[]>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var tokens = Tokenize(sentence);
            tokensBySentence.Add(tokens);
            foreach (var token in tokens)
            {
                if (!StopWords.Contains(token))
                    wordFreq[token] = wordFreq.GetValueOrDefault(token) + 1;
            }
        }

        // Score each sentence by the sum of its word frequencies.
        var scored = sentences
            .Select((s, i) =>
            {
                double score = tokensBySentence[i]
                    .Where(t => !StopWords.Contains(t))
                    .Sum(t => wordFreq.GetValueOrDefault(t));
                return (Index: i, Score: score);
            })
            .OrderByDescending(x => x.Score)
            .Take(keep)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => sentences[x.Index]);

        var summary = string.Join(" ", scored);

        return new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = keep
        };
    }

    private static string[] Tokenize(string sentence)
    {
        var cleaned = PunctuationStripper().Replace(sentence, "");
        return cleaned.Split(' ', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(ISummarizationService summarizationService) : ControllerBase
{
    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var result = summarizationService.Summarize(request.Text, request.MaxSentences);
        return Ok(result);
    }
}

